import React from "react";
import classes from './Header.module.css';
import {NavLink} from "react-router-dom";
import logo from "../img/Logo2.png";



const Header = (props) => {
     return <div className={classes.header}>
<div className={classes.headerContent}>
    {/*<NavLink to='/log' className={classes.headerText}>SAIL</NavLink>*/}
    <NavLink to='/log' className={classes.headerText}><img className={classes.headerText} src={logo} alt='logo' /> </NavLink>
    <div className={classes.langru}>
        <NavLink to='/ru' activeClassName={classes.active}>RU</NavLink>
    </div>
    <div className={classes.langen}>
        <NavLink to='/en' activeClassName={classes.active}>EN</NavLink>
    </div>
    <div className={classes.log}>
        {props.isAuth
            ? <div className={classes.loginned}> <button onClick={props.logout}>LOG  OUT</button> {props.login} {props.id} </div>
            : <div className={classes.log}>
            <NavLink to='/log' activeClassName={classes.active}>LOG  IN</NavLink>
        </div>}
            </div>

</div>
        </div>
}

export default Header;
